// TestExtractSingleObjectArraySibling pins the relaxed-tolerance contract:
// unknown scalar siblings (timestamps, request IDs, version stamps, etc.)
// must be skipped rather than treated as disqualifying. The earlier
// implementation early-bailed on any non-array key not in
// pageEnvelopeMetadataKeys, which silently dropped pages for many real-world
// envelope shapes — e.g. {"tenders": [...], "generated_at": "...",
// "request_id": "..."}.
func TestExtractSingleObjectArraySibling(t *testing.T) {
	t.Parallel()

	mustRaw := func(s string) json.RawMessage { return json.RawMessage(s) }

	cases := []struct {
		name     string
		envelope map[string]json.RawMessage
		wantOK   bool
		wantLen  int
	}{
		{
			name: "single object array with unknown scalar siblings",
			envelope: map[string]json.RawMessage{
				"tenders":      mustRaw(`[{"id":"t-1"},{"id":"t-2"}]`),
				"generated_at": mustRaw(`"2024-01-01T00:00:00Z"`),
				"request_id":   mustRaw(`"abc-123"`),
				"api_version":  mustRaw(`"v2"`),
			},
			wantOK:  true,
			wantLen: 2,
		},
		{
			name: "single object array with known metadata siblings (cursor, has_more)",
			envelope: map[string]json.RawMessage{
				"markets":  mustRaw(`[{"id":"m-1"}]`),
				"cursor":   mustRaw(`"next-page"`),
				"has_more": mustRaw(`true`),
			},
			wantOK:  true,
			wantLen: 1,
		},
		{
			name: "single object array with null sibling",
			envelope: map[string]json.RawMessage{
				"results":  mustRaw(`[{"id":"r-1"}]`),
				"next":    mustRaw(`null`),
			},
			wantOK:  true,
			wantLen: 1,
		},
		{
			name: "ambiguous: two qualifying object arrays",
			envelope: map[string]json.RawMessage{
				"primary":   mustRaw(`[{"id":"p-1"}]`),
				"secondary": mustRaw(`[{"id":"s-1"}]`),
			},
			wantOK:  false,
			wantLen: 0,
		},
		{
			name: "no object arrays at all",
			envelope: map[string]json.RawMessage{
				"status":  mustRaw(`"ok"`),
				"latency": mustRaw(`42`),
			},
			wantOK:  false,
			wantLen: 0,
		},
		{
			name: "scalar arrays are not object arrays and are ignored",
			envelope: map[string]json.RawMessage{
				"items": mustRaw(`[{"id":"i-1"}]`),
				"tags":  mustRaw(`["a","b","c"]`),
			},
			wantOK:  true,
			wantLen: 1,
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			items, ok := extractSingleObjectArraySibling(tc.envelope)
			if ok != tc.wantOK {
				t.Fatalf("ok = %v, want %v (items=%v)", ok, tc.wantOK, items)
			}
			if len(items) != tc.wantLen {
				t.Fatalf("len(items) = %d, want %d", len(items), tc.wantLen)
			}
			// Sanity: when we expect to find items, the first one must be a
			// non-nil object.
			if tc.wantOK && tc.wantLen > 0 {
				if reflect.ValueOf(items[0]).IsZero() {
					t.Errorf("first item is zero-value json.RawMessage")
				}
			}
		})
	}
}
